#include <iostream>
#include <cstdio>
#include <cstdlib>
using namespace std;

struct ListNode{
    int val;
    ListNode* prev;
    ListNode* next;
    ListNode(int x) : val(x), prev(nullptr), next(nullptr) {}
};

class Solution{
public:
    ListNode* solve(ListNode* head1, ListNode* head2){
        // Reverse the linked list
        head1 = reverse(head1);

        // Merge the linked lists
        ListNode dummy(0);
        ListNode* current = &dummy;

        while (head1 && head2){
            if (head1->val <= head2->val){
                current->next = head1;
                head1 = head1->next;
            } else {
                current->next = head2;
                head2 = head2->next;
            }
            current = current->next;
        }

        head1 = head1 or head2;

        // Correctly return the merged and sorted linked list
        return head1;
    }

    ListNode* reverse(ListNode* head){
        ListNode* prev = nullptr;
        while (head){
            ListNode* next_node = head->next;
            head->next = prev;
            head->prev = next_node;
            prev = head;
            head = next_node;
        }
        return prev;
    }
};

